class Solution {
public:
    string sortString(string s) {
        int count[26] = {0};
        for (char c : s) {
            count[c - 'a']++;
        }

        string result;
        while (s.size() > 0) {
            // append smallest character
            for (int i = 0; i < 26; i++) {
                if (count[i] > 0) {
                    result += 'a' + i;
                    count[i]--;
                    s.erase(s.find('a' + i), 1);
                }
            }

            // append largest character
            for (int i = 25; i >= 0; i--) {
                if (count[i] > 0) {
                    result += 'a' + i;
                    count[i]--;
                    s.erase(s.find('a' + i), 1);
                }
            }
        }

        return result;
    }
};
```
